import React from 'react'
import useBook from '../hooks/useBook'
import Loading from './Loading'
import { Link } from 'react-router-dom';
import { Container, Grid, Card, CardMedia, CardContent, Typography } from '@mui/material';

const Search = () => {

    const { bookData, loading } = useBook()

    const cardBook = {
      height: '240px',
    }


  return (
        <>
            {
             loading ? <Loading /> :
             <Container fluid="true">
             <Grid ml="auto" mr="auto" mb="2rem" container spacing={1} >
               {Array.from(bookData).map((item, index) => (
                 <Grid item key={index} xs={6} sm={4} md={3} lg={2}>
                   {item.volumeInfo.imageLinks ? (
                     <Link to={`../book/${index}`}>
                       <Card sx={cardBook}>
                         <CardMedia
                           component="img"
                           alt={item.volumeInfo.title}
                           height="240"
                           image={item.volumeInfo.imageLinks.thumbnail}
                         />
                       </Card>
                     </Link>
                   ) : (
                     <Card sx={cardBook}>
                       <CardContent>
                         <Typography variant="h6" component="div" className="search-card-title">
                           {item.volumeInfo.title}
                         </Typography>
                         <Typography variant="subtitle1" className="search-card-author">
                           {item.volumeInfo.authors}
                         </Typography>
                         <Typography variant="subtitle2" className="search-card-publisher">
                           {item.volumeInfo.publisher}
                         </Typography>
                         <CardMedia component="img" src="../img/logo.png" height="100%" alt="Logo de Biblios" />
                       </CardContent>
                     </Card>
                   )}
                 </Grid>
               ))}
             </Grid>
           </Container>
            }
        </>
  )
}

export default Search
